<?php
const THIS_PAGE = 'external_video';
require __DIR__.'/includes/config.inc.php';
require_once __DIR__.'/../custom/external_videos/lib/external_videos_lib.php';
$slug=$_GET['slug']??'';
$v=ev_get_by_slug($slug);
if(!$v){ http_response_code(404); echo 'Not found'; exit; }
ev_increment_view((int)$v['id']);
$canonical='/external_video.php?slug='.rawurlencode($v['slug']);
$mediaUrl=$v['download_url'] ?: $v['embed_url'];
$isHls=(bool)preg_match('/\.m3u8(\?|$)/i',$mediaUrl);

function ev_lang_switcher(): string {
    $current = Language::getInstance()->getLangISO();
    $path = parse_url($_SERVER['REQUEST_URI'] ?? '/', PHP_URL_PATH) ?: '/';
    parse_str($_SERVER['QUERY_STRING'] ?? '', $params);
    $params['set_site_lang'] = '1';
    $enUrl = $path . '?' . http_build_query($params);
    $params['set_site_lang'] = 'zh-CN';
    $zhUrl = $path . '?' . http_build_query($params);
    return '<form class="oc-lang-switcher" method="get" action="'.ev_h($path).'"><label for="oc-lang-select">'.ev_h(lang('oc_language')).'</label><select id="oc-lang-select" name="set_site_lang" onchange="window.location.href=this.value"><option value="'.ev_h($enUrl).'"'.($current==='en'?' selected':'').'>English</option><option value="'.ev_h($zhUrl).'"'.(($current==='zh-CN'||$current==='zh')?' selected':'').'>中文</option></select></form>';
}
?><!doctype html><html lang="<?=ev_h(Language::getInstance()->getLangISO())?>"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title><?=ev_h($v['title'])?></title><meta name="description" content="<?=ev_h(mb_substr(strip_tags($v['description']??''),0,155))?>"><link rel="canonical" href="<?=ev_h($canonical)?>"><link rel="stylesheet" href="/styles/cb_28/theme/css/portal.css?v=20260629"><link rel="stylesheet" href="/styles/cb_28/theme/css/external-videos.css?v=5"><style>.external-player video{width:100%;height:100%;background:#000;border:0;border-radius:14px}.external-player .fallback{padding:24px;background:#111;color:#fff;border-radius:14px}</style></head><body class="portal-shell"><nav class="oc-portal-nav" style="position:static"><a href="/"><?=ev_h(lang('oc_home'))?></a><a href="/external_feed.php"><?=ev_h(lang('oc_videos'))?></a><a href="/videos.php"><?=ev_h(lang('oc_hosted_videos'))?></a><a href="/dmca.php"><?=ev_h(lang('oc_dmca'))?></a><?=ev_lang_switcher()?></nav><main class="external-watch"><div class="external-grid"><section><div class="external-player"><?php if($isHls): ?><video id="external-hls-player" controls playsinline preload="metadata" poster="<?=ev_h($v['thumbnail_url']??'')?>"></video><noscript><p class="fallback"><a rel="nofollow noopener noreferrer" href="<?=ev_h($mediaUrl)?>"><?=ev_h(lang('oc_open_video_stream'))?></a></p></noscript><?php else: ?><?=ev_iframe($v)?><?php endif; ?></div><h1><?=ev_h($v['title'])?></h1><div class="meta"><?=number_format((int)$v['view_count']+1)?> <?=ev_h(lang('oc_views'))?> · <?=ev_h($v['provider'])?> · <?=ev_h($v['created_at'])?> <?=((int)$v['is_18_plus']?' · 18+':'')?></div><p><?=nl2br(ev_h($v['description']))?></p><div class="chips"><?php foreach(array_filter(array_map('trim',explode(',',$v['tags']??''))) as $tag): ?><a href="/external_feed.php?q=<?=rawurlencode($tag)?>"><?=ev_h($tag)?></a><?php endforeach;?></div><p><?=ev_h(lang('oc_source'))?>: <a rel="nofollow noopener noreferrer" target="_blank" href="<?=ev_h($v['source_url'])?>"><?=ev_h(parse_url($v['source_url'],PHP_URL_HOST)?:$v['provider'])?></a></p><p class="actions"><a href="/report-abuse.php"><?=ev_h(lang('oc_report'))?></a> · <a href="/dmca.php"><?=ev_h(lang('oc_dmca_complaint'))?></a> · <a href="/content-removal.php"><?=ev_h(lang('oc_content_removal'))?></a></p></section><aside><h2><?=ev_h(lang('oc_recommended'))?></h2><?php foreach(ev_list(['published'=>1,'imported_only'=>1,'limit'=>8]) as $r): if($r['id']==$v['id'])continue; ?><p><a href="/external_video.php?slug=<?=rawurlencode($r['slug'])?>"><?=ev_h($r['title'])?></a></p><?php endforeach;?></aside></div></main><?php if($isHls): ?><script src="https://cdn.jsdelivr.net/npm/hls.js@1"></script><script>const src=<?=json_encode($mediaUrl, JSON_UNESCAPED_SLASHES)?>,v=document.getElementById('external-hls-player');if(v){if(v.canPlayType('application/vnd.apple.mpegurl')){v.src=src}else if(window.Hls&&Hls.isSupported()){const h=new Hls({maxBufferLength:30});h.loadSource(src);h.attachMedia(v)}else{v.outerHTML='<p class="fallback"><a rel="nofollow noopener noreferrer" href="'+src+'"><?=addslashes(ev_h(lang('oc_open_video_stream')))?></a></p>'}}</script><?php endif; ?><script src="/external_age_gate.js"></script></body></html>
